var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"18시간 후. 북방합의체 영토권. 시베리아 중부, 봉쇄 균열.","JPN":"18時間後。北方合意体領土圏。シベリア中部、封鎖亀裂。","ENG":"Eighteen hours later. Northern Union Territory. Central Siberia, Sealed Crevice.","TWN":"18小時後，北方和議會領土圈，西伯利亞中部、封鎖大峽谷。","DEU":"Eighteen hours later. Northern Union Territory. Central Siberia, Sealed Crevice.","FRA":"Eighteen hours later. Northern Union Territory. Central Siberia, Sealed Crevice."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 지정 코드명- <color=#ffd34c>그라운드 제로</color>","JPN":"管理局指定コードネーム - <color=#ffd34c>グラウンド・ゼロ</color>","ENG":"Administration-appointed Codename- <color=#ffd34c>Ground Zero</color>","TWN":"管理局指定代號 - <color=#ffd34c>Ground Zero</color>","DEU":"Administration-appointed Codename- <color=#ffd34c>Ground Zero</color>","FRA":"Administration-appointed Codename- <color=#ffd34c>Ground Zero</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님. 보고드립니다.","JPN":"中将、報告します。","ENG":"Lieutenant General, reporting in.","TWN":"中將，報告。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"현재 위치하신 C2 섹터에서 D5섹터까지, 북방합의체의 특이동향은 발견되지 않았습니다.","JPN":"現在いらっしゃるC2セクターよりD5セクターまで、北方合意体の特筆すべき動向は観測されていません。","ENG":"From our current position in Sector C2 to Sector D5, no unusual Northern Union activity detected.","TWN":"從您目前所在的C2區域到D5區域，尚未發現北方和議會的異常動向。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 최근 침입자가 발생했다는 이유로 경비가 삼엄할 줄 알았는데 예상외로 순탄하군.","JPN":"ああ。最近あったという侵入者発生の影響で警備が厳しくなっていると予想したが、案外順調だな。","ENG":"I see. I expected tighter security after the recent intrusions, but things are smoother than expected.","TWN":"好，還以為警備會因為最近有人入侵變得森嚴，結果卻意外順利。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"덕분에 불필요한 충돌은 피할 수 있겠어.","JPN":"おかげで、不要な衝突は避けられそうだ。","ENG":"All the better to avoid unnecessary clashes.","TWN":"多虧如此，應該能省去不必要的出動。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇지만… 정말 괜찮을까요?","JPN":"ですが……本当に大丈夫でしょうか？","ENG":"Still... Are we really fine with this?","TWN":"但是…真的沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 군사학이나 집단간의 복잡한 이해관계에 관해 중장님만큼 해박하지 않습니다.","JPN":"私は軍事学や、集団同士の複雑な利害関係について中将ほど詳しくありません。","ENG":"I'm not as versed in military science or complex intergroup interests as you are.","TWN":"無論是軍事學或群體間複雜的利害關係，我都沒有中將這麼淵博。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 양측 지휘관끼리 독대하고 싶다는 합의체의 요구는 비정상적이라고 생각해요.","JPN":"ですが、指揮官同士で会談の場を持ちたいという合意体の要求は異常だと思います。","ENG":"But the Northern Union insisting on a one-on-one between commanders feels abnormal.","TWN":"但我認為和議會要求雙方指揮官單獨會面是不正常的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국의 특수전사령부가 움직였으니 경계심이 올라가는 건 당연하지.","JPN":"合衆国の特殊戦司令部が動いたんだ。警戒を強めるのは当然のことだ。","ENG":"The States Strategic Special Operations Command is mobilizing. Of course their guard is up.","TWN":"既然合眾國特種作戰司令部已經採取行動，當然就要提高警戒。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우릴 상대로 전쟁이라도 벌일 심산이 아닌 이상, 자네 걱정처럼 되지는 않을 거야.","JPN":"我々を相手に戦争を起こすつもりでもない限り、君の心配してるようなことにはならないだろう。","ENG":"Unless they plan to wage war on us, your worst-case will not come to pass.","TWN":"除非是想和我們開戰，否則事情應該不會演變成妳擔心的那樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"무엇보다 싸울 <color=#ffd34c>준비</color>라면 이미 끝마치지 않았나?","JPN":"何より、戦う<color=#ffd34c>準備</color>ならもう済ませているじゃないか。","ENG":"Above all, our <color=#ffd34c>preparations</color> to fight are complete, are they not?","TWN":"最重要的是，我們不是已經做好戰鬥的<color=#ffd34c>準備</color>了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……죄송해요. 중장님을 믿지 못한다는 소리는 아니었어요.","JPN":"……申し訳ありません。中将のことを信用できないという意味ではありませんでした。","ENG":"...My apologies. I didn't mean I don't trust you.","TWN":"……抱歉，我的意思不是信不過中將。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"천만에. 나도 자네가 있으니 이런 대담한 짓을 벌일 수 있는 걸세.","JPN":"いや。私にこんな大胆な真似ができるのは、君がいてくれるおかげだ。","ENG":"Think nothing of it. With you here, I can afford to be this bold.","TWN":"別這麼說，我也是因為有妳在，才能做出這種大膽的事。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"신원 확인. 마리아 안토노프 중장의 출입을 허락합니다.","JPN":"身元確認。マリア・アントノフ中将の入室を許可します。","ENG":"Identity confirmed. Lieutenant General Maria Antonov is cleared to enter.","TWN":"身分確認，允許瑪麗亞·安東諾夫中將進入。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"각하께서 계신 방으로 모시겠습니다, 이쪽으로.","JPN":"閣下の部屋までご案内します。こちらへ。","ENG":"I will escort you to the General's room. This way.","TWN":"我帶您到閣下的房間，請往這邊走。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼…….","JPN":"では……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"다시 연락하지, 제이나.","JPN":"また連絡する、ジェイナ。","ENG":"I'll be in touch, Jaina.","TWN":"再聯絡吧，婕娜。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"메모리 아카이브 동기화–– 데이터 정렬 완료.","JPN":"メモリーアーカイブ同期化──データ整列完了。","ENG":"Memory archive synchronization–– Data alignment complete.","TWN":"記憶體存檔同步––資料排序完畢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"사용자의 기억 체계에 따른 가상현실 구축 프로토콜 실행합니다.","JPN":"使用者の記憶体系による仮想現実構築プロトコルを実行します。","ENG":"Initializing VR construction protocol based on the user's memory schema.","TWN":"根據使用者的記憶系統執行虛擬現實構建協議。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"반복 횟수–––– ■■■■■번.","JPN":"反復回数────■■■■■回。","ENG":"Iteration count–––– ■■■■■ times.","TWN":"反覆次數–––– ■■■■■次。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"여기는 시렌 추격전대…! 단방향 송신기를 통해 본부로 긴급 상황을 전파합니다!","JPN":"こちら、シレン追撃戦隊……！　単方向の送信機を通じて本部に緊急状況をお伝えします！","ENG":"This is the Sirin Tracking Division...! Sending an emergency message to HQ through a one-way transmitter!","TWN":"這裡是賽蓮追擊戰隊…！透過單向發送器向本部發送緊急情況！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"사도의 전력이 예상한 것보다 압도적으로 강합니다…!","JPN":"使徒の戦力が予想よりも圧倒的に強いです……！","ENG":"The Apostle's power is overwhelmingly more powerful than we expected...!","TWN":"使徒的戰力比預期還要強太多了…！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리 전대는 궤멸에 가까운 타격을 입었고…! 생존한 대원들은 시간을 벌 수 있도록 산개했습니다!","JPN":"こちらの戦隊は壊滅に近いダメージを受け……！　生き残った隊員たちは時間を稼げるように散開中であります！","ENG":"Our division has suffered a critical blow that was close to annihilation...! The surviving members have been ordered to scatter to buy more time!","TWN":"我們的戰隊遭受了近乎毀滅的打擊…！倖存隊員則是分散開來爭取時間！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"승산은 없습니다! 격리된 사도는 예정보다 빨리 풀려날 겁니다!","JPN":"勝ち目はありません！　隔離された使徒は予定より早く解放されるでしょう！","ENG":"There is no hope! The isolated Apostle will be released sooner than expected!","TWN":"毫無勝算！被隔離的使徒會比預期更快被釋放！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"펜릴이 마왕을 서둘러 처치하지 않으면…!","JPN":"早くフェンリルが魔王を始末しないと……！","ENG":"If the Fenrir doesn't defeat the Demon Lord soon...!","TWN":"要是芬里爾不盡快消滅魔王的話…！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"크윽…!","JPN":"ううっ……！","ENG":"Kgh...!","TWN":"咳呃…！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"숨을 수 있을 줄 알았어?","JPN":"隠れられるとでも思ったのか？","ENG":"Did you really think you could hide from me?","TWN":"妳以為自己躲得了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"그렇게 피를 흘리고 있으면, 냄새로 찾아낼 수밖에 없잖아. 사냥감.","JPN":"それだけ血を流してたら、匂いで探せるんだ。獲物。","ENG":"I can smell you right away when you're bleeding that much, prey.","TWN":"要是那樣流血的話，就只能憑藉味道找出來了，獵物。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"날… 먼저 쫓아온 건가?","JPN":"私を……先に狙って来たのか？","ENG":"Did you... come after me first?","TWN":"難道…你ˋ是先追著我來嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_WOLF","text":{"KOREA":"아니? 다른 녀석들은 진작에 처리했는데?","JPN":"いや？　他の奴らはすでに始末した。","ENG":"No. I already took care of the others a long time ago.","TWN":"不，我早就把其他傢伙消滅了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_WOLF","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};